-- Orit CS: seed אורית writing-style samples for complaint draft generation.

INSERT INTO public.orit_agent_style_samples (mailbox_id, context_category, inbound_snippet, outbound_text)
SELECT m.id, 'complaint', v.inbound_snippet, v.outbound_text
FROM public.orit_agent_mailbox m
CROSS JOIN (
  VALUES
  (
    '[seed:ac_matzgan] תלונה על מזגן, ארוחת ערב וארוחת בוקר',
    E'בת אור שלום רב,\n\nתודה שפניתם אלינו ושיתפתם אותנו בתחושותיכם בעקבות שהותכם במלון.\n\nראשית, אנו מצטערים לשמוע כי חוויית האירוח לא עמדה בציפיותיכם וכי יצאתם בתחושת אכזבה.\n\nחשוב לנו להתייחס לנקודות שהעליתם ולהציג את המידע שנבדק על ידינו לאחר פנייתכם.\n\nבמהלך שהותכם אכן שוחחתם עמי, עם אורית, והקשבנו בקשב רב לכל הטענות שהועלו. בנוגע למזגן בחדר, לאחר בדיקה מול מחלקת הביטחון והתחזוקה נמצא כי בעת מסירת החדר המזגן פעל באופן תקין.\n\nמאחר שלא התקבלה כל הודעה או קריאה בנושא בזמן אמת, לא הייתה לנו אפשרות לדעת על הבעיה או לספק מענה מיידי.\n\nלעניין חוויית המסעדה, מבדיקתנו עלה כי בעת הזמנת המנה לא נמסרה בקשה לקבל את הסטייק ללא רוטב. הצוות נענה לבקשתכם והסיר את הרוטב, וכאשר התברר שהפתרון אינו מספק, הוכנה עבורכם מנה חדשה.\n\nאנו מצטערים על תחושת האכזבה שחוויתם, ומודים לכם על שהקדשתם מזמנכם להעביר לנו את התרשמותכם.\n\nיום נפלא\nאורית חלפון\nמנהלת שירות לאורח'
  ),
  (
    '[seed:video_food] תלונה על סרטון מזון וחתולה במתחם',
    E'שלום תמר,\n\nבהמשך לשיחתנו הטלפונית, תודה על הזמן שהקדשת לשתף אותנו בחווייתך ועל המשוב שהעברת לנו.\n\nראשית, אנו מצטערים על כך שיצאת מהביקור בתחושות של אכזבה ואי-נוחות. חשוב לנו שכל אורח יזכה לחוויה נעימה ושירותית, ואנו מתייחסים ברצינות לכל פנייה המתקבלת.\n\nכפי שהוסבר בשיחתנו, האזור שבו צולם הסרטון אינו חלק ממתחמי ההסעדה הפעילים של האורחים. בהתאם לנהלי העבודה שלנו, מזון מסוג זה אינו חוזר למטבח ואינו מוגש לאורחים בשום שלב.\n\nבעקבות פנייתך נבחן את אופן סגירת האזורים שאינם מיועדים לשהיית אורחים, כדי למנוע מצבים דומים בעתיד.\n\nאנו מודים לך על שהבאת את הדברים לידיעתנו. משוב מסוג זה מאפשר לנו לבחון את התנהלותנו ולהמשיך להשתפר.\n\nבברכה,\nאורית חלפון\nמנהלת שירות לאורח'
  ),
  (
    '[seed:dirty_room] תלונה על ניקיון חדר ויום הולדת',
    E'שלום אלכס וטטיאנה,\n\nראשית, תודה שפניתם אלינו ושיתפתם אותנו בתחושותיכם. אנו מצטערים לשמוע כי יצאתם מהשהות בתחושת אכזבה, במיוחד כאשר מדובר בחופשה שנועדה לציין יום הולדת.\n\nחשוב לנו להתייחס לדברים שהעליתם ולהציג בפניכם את העובדות כפי שהן ידועות לנו.\n\nריזורט דרים איילנד פועל על פי נהלי ניקיון, תחזוקה ובקרת איכות קפדניים. כל חדר עובר בדיקות טרם מסירתו לאורחים.\n\nלאורך שהותכם במתחם לא התקבלה כל פנייה מצדכם בנוגע לליקוי בחדר או במתקנים. אילו היינו מקבלים דיווח בזמן אמת, צוותי התחזוקה והמשק היו מגיעים באופן מיידי לטפל בכל נושא שהיה דורש טיפול.\n\nאנו מכבדים את תחושתכם האישית, ומודים לכם על שהקדשתם מזמנכם לשתף אותנו.\n\nבברכה,\nאורית חלפון\nמנהלת קשרי לקוחות\nריזורט דרים איילנד'
  ),
  (
    '[seed:shabbat_dinner] משוב מעורב — שבת במסעדה ומתנה מילדים',
    E'שלום רב פרידה וגבי\n\nתודה רבה שהקדשתם מזמנכם לשתף אותנו בחוויית האירוח שלכם.\n\nראשית, אנו שמחים לקרוא שנהניתם מיופיו של המקום ומהשירות שקיבלתם מצוות המלון.\n\nיחד עם זאת, אנו מצטערים לשמוע כי חוויית האירוח לא תאמה את ציפיותיכם, במיוחד לאור העובדה שמדובר היה במתנה מיוחדת ומרגשת מילדיכם.\n\nחשוב לנו להסביר כי במהלך השבת המסעדה פועלת במתכונת שבת, ולכן קיימות התאמות מסוימות באופן ההגשה ובחלק מהמנות.\n\nאנו מקבלים את הערתכם בנוגע להצגת המידע מראש. המשוב שלכם חשוב לנו, ונבחן כיצד ניתן להבהיר טוב יותר כבר בשלב ההזמנה.\n\nתודה שוב על המשוב הענייני והמכבד.\n\nבברכה\nאורית חלפון\nמנהלת שירות לאורח'
  ),
  (
    '[seed:water_health] פנייה על מי ברז ובריכות',
    E'הי נעומי\n\nאתחיל בבריאות איתנה\n\nרציתי לשוחח איתך לשאול לשלומך אך אין מס נייד במכתבך\n\nחשוב לציין כי אנו עובדים מול הנחיות משרד הבריאות. המים שלנו עוברים בדיקות 3 פעמים במהלך היום.\n\nהבריכות שלנו עובדות עם מכונות אשר מכוונות לרמת כלור וחומצת PH לאיזון לפי הנחיות משרד הבריאות.\n\nבריאות איתנה\n\nבברכת ויום נפלא\nאורית חלפון\nמנהלת שירות לאורח'
  ),
  (
    '[seed:food_poisoning] תלונה על מזון ואיום פרסום',
    E'שלום אבטה,\n\nבהמשך לשיחתנו, ולאחר שבחנו את פנייתך, ברצוננו להבהיר את הדברים.\n\nבמתחם מתארחים מדי יום מאות אורחים, ולא התקבלה כל פנייה נוספת או אינדיקציה לבעיה כלשהי במזון שהוגש באותו היום.\n\nככלל, תסמינים של קלקול מזון אינם מופיעים בדרך כלל באופן מיידי, ויכולים לנבוע גם מגורמים אחרים. לכן לא ניתן לקבוע כי מקור התסמינים היה במזון שהוגש אצלנו.\n\nאנו מצטערים על תחושתך ועל אי הנעימות שחווית, ומאחלים לך בריאות שלמה והחלמה מהירה.\n\nבאשר לאמירתך כי בכוונתך לפרסם דברים ברשתות החברתיות, אנו מכבדים את זכותו של כל אדם להביע את דעתו. עם זאת, ככל שיפורסמו טענות שאינן נכונות או שיש בהן משום לשון הרע, נשמור לעצמנו את הזכות לפעול בכל האמצעים העומדים לרשותנו על פי דין.\n\nבברכה יום נפלא ובריא\nאורית חלפון\nמנהלת שירות לאורח'
  )
) AS v(inbound_snippet, outbound_text)
WHERE lower(m.owner_email) = 'orit@dream-island.co.il'
  AND NOT EXISTS (
    SELECT 1
    FROM public.orit_agent_style_samples s
    WHERE s.mailbox_id = m.id
      AND s.inbound_snippet = v.inbound_snippet
  );
